1	/**
2	 * Vault Transactions API
3	 */
4	
5	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
6	import {
7	  logRouteFetch,
8	  logRouteError,
9	  extractUserFromRequest,
10	} from '@/app/api/lib/utils/routeLogger';
11	import { getMoneyOutAndJackpotScale } from '@/app/api/lib/utils/reviewerScale';
12	import type { ExtendedVaultTransaction } from '@/shared/types/vault';
13	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
14	import { NextRequest, NextResponse } from 'next/server';
15	import { GamingLocations } from '../../lib/models/gaminglocations';
16	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
17	import type {
18	  GamingMachine,
19	  GamingLocationDocument,
20	  VaultTransactionDocument,
21	} from '@shared/types';
22	import type { LeanUserDocument } from 'shared/types/auth';
23	
24	/**
25	 * Main GET handler for vault transactions.
26	 *
27	 * STEP 1: Authorization and permission check.
28	 * STEP 2: Parse query parameters (locationId, page, limit, type, status, search).
29	 * STEP 3: Handle location authorization filtering.
30	 * STEP 4: Build database query based on filters.
31	 * STEP 5: Fetch transactions and total count from DB.
32	 * STEP 6: Enrich transactions with location, user, and machine details.
33	 * STEP 7: Apply reviewer multiplier scaling if applicable.
34	 * STEP 8: Return formatted response with pagination.
35	 *
36	 * @param {NextRequest} request - The incoming Next.js request.
37	 * @param {string} request.url - URL containing searchParams:
38	 *   - locationId: Filter by location ID (or 'all').
39	 *   - page: Page number for pagination (default: 1).
40	 *   - limit: Items per page (default: 20, max: 100).
41	 *   - type: Filter by transaction type(s) (comma-separated).
42	 *   - status: Filter by status (e.g., 'voided').
43	 *   - search: Generic search query for notes/metadata.
44	 * @returns {Promise<NextResponse>} Paginated vault transaction list with enriched metadata.
45	 */
46	export async function GET(request: NextRequest) {
47	  const startTime = Date.now();
48	  const functionName = 'GET /api/vault/transactions';
49	  const user = extractUserFromRequest(request);
50	
51	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
52	    try {
53	      const normalizedRoles = userRoles.map(r => String(r).toLowerCase());
54	      const hasVMAccess = normalizedRoles.some(role =>
55	        ['developer', 'admin', 'manager', 'vault-manager'].includes(role)
56	      );
57	      if (!hasVMAccess) {
58	        logRouteError(
59	          functionName,
60	          'GET',
61	          '/api/vault/transactions',
62	          'Insufficient permissions',
63	          user
64	        );
65	        return NextResponse.json(
66	          { success: false, error: 'Insufficient permissions' },
67	          { status: 403 }
68	        );
69	      }
70	
71	      const { searchParams } = new URL(request.url);
72	      const locationId = searchParams.get('locationId');
73	      const page = parseInt(searchParams.get('page') || '1');
74	      const limit = Math.min(parseInt(searchParams.get('limit') || '20'), 100);
75	      const skip = (page - 1) * limit;
76	
77	      const allowedLocationIds = await getUserLocationFilter(
78	        (userPayload?.assignedLicencees as string[]) || [],
79	        undefined,
80	        (userPayload?.assignedLocations as string[]) || [],
81	        userRoles
82	      );
83	
84	      const query: Record<string, unknown> = {};
85	      if (!locationId || locationId === 'all') {
86	        if (allowedLocationIds !== 'all')
87	          query.locationId = { $in: allowedLocationIds };
88	      } else {
89	        if (
90	          allowedLocationIds !== 'all' &&
91	          !allowedLocationIds.includes(locationId)
92	        ) {
93	          logRouteError(
94	            functionName,
95	            'GET',
96	            '/api/vault/transactions',
97	            'Access denied',
98	            user
99	          );
100	          return NextResponse.json(
101	            { success: false, error: 'Access denied' },
102	            { status: 403 }
103	          );
104	        }
105	        query.locationId = locationId;
106	      }
107	
108	      const type = searchParams.get('type');
109	      const status = searchParams.get('status');
110	      const search = searchParams.get('search');
111	
112	      if (type && type !== 'all')
113	        query.type = type.includes(',') ? { $in: type.split(',') } : type;
114	      if (status && status !== 'all') query.isVoid = status === 'voided';
115	
116	      if (search) {
117	        const sr = { $regex: search, $options: 'i' };
118	        const orConditions: Record<string, unknown>[] = [
119	          { notes: sr },
120	          { auditComment: sr },
121	          { performedBy: sr },
122	        ];
123	        const ns = parseFloat(search);
124	        if (!isNaN(ns)) orConditions.push({ amount: ns });
125	        query.$or = orConditions;
126	      }
127	
128	      const [transactions, total] = await Promise.all([
129	        VaultTransactionModel.find(query)
130	          .sort({ timestamp: -1 })
131	          .skip(skip)
132	          .limit(limit)
133	          .lean<VaultTransactionDocument[]>(),
134	        VaultTransactionModel.countDocuments(query),
135	      ]);
136	
137	      let finalTx: ExtendedVaultTransaction[] =
138	        transactions as unknown as ExtendedVaultTransaction[];
139	      if (locationId === 'all' || !locationId) {
140	        const locIds = transactions.map(tx => tx.locationId);
141	        const locations = await GamingLocations.find(
142	          { _id: { $in: locIds } },
143	          { _id: 1, name: 1 }
144	        )
145	          .lean<GamingLocationDocument[]>()
146	          .then(loc => loc.map(l => ({ _id: String(l._id), name: l.name })));
147	        const nMap = locations.reduce(
148	          (acc, loc) => {
149	            acc[loc._id] = loc.name;
150	            return acc;
151	          },
152	          {} as Record<string, string>
153	        );
154	        finalTx = transactions.map(tx => ({
155	          ...(tx as unknown as Record<string, unknown>),
156	          locationName: nMap[tx.locationId] || 'Unknown',
157	        })) as unknown as ExtendedVaultTransaction[];
158	      }
159	
160	      const uIds = new Set<string>();
161	      const mIds = new Set<string>();
162	      finalTx.forEach(tx => {
163	        if (tx.performedBy) uIds.add(tx.performedBy);
164	        const from = tx.from;
165	        const to = tx.to;
166	        if (from?.type === 'cashier' && from.id) uIds.add(from.id);
167	        if (to?.type === 'cashier' && to.id) uIds.add(to.id);
168	        if (from?.type === 'machine' && from.id) mIds.add(from.id);
169	        if (to?.type === 'machine' && to.id) mIds.add(to.id);
170	        if (tx.expenseDetails?.machineIds?.length)
171	          tx.expenseDetails.machineIds.forEach(id => mIds.add(id));
172	      });
173	
174	      const [userMap, machineMap] = await Promise.all([
175	        uIds.size
176	          ? (await import('@/app/api/lib/models/user')).default
177	              .find(
178	                { _id: { $in: Array.from(uIds) } },
179	                { 'profile.firstName': 1, 'profile.lastName': 1, username: 1 }
180	              )
181	              .lean<LeanUserDocument[]>()
182	              .then(users =>
183	                users.reduce(
184	                  (acc, u) => {
185	                    acc[String(u._id)] = u as Record<string, unknown>;
186	                    return acc;
187	                  },
188	                  {} as Record<string, Record<string, unknown>>
189	                )
190	              )
191	          : Promise.resolve({} as Record<string, Record<string, unknown>>),
192	        mIds.size
193	          ? (await import('@/app/api/lib/models/machines')).Machine.find(
194	              { _id: { $in: Array.from(mIds) } },
195	              {
196	                serialNumber: 1,
197	                'custom.name': 1,
198	                game: 1,
199	                installedGame: 1,
200	                gameType: 1,
201	              }
202	            )
203	              .lean<GamingMachine[]>()
204	              .then(machines =>
205	                machines.reduce(
206	                  (acc, m) => {
207	                    acc[String(m._id)] = m as Record<string, unknown>;
208	                    return acc;
209	                  },
210	                  {} as Record<string, Record<string, unknown>>
211	                )
212	              )
213	          : Promise.resolve({} as Record<string, Record<string, unknown>>),
214	      ]);
215	
216	      const populated = finalTx.map(tx => {
217	        const res: Record<string, unknown> = {
218	          ...(tx as unknown as Record<string, unknown>),
219	        };
220	        const performedByKey = tx.performedBy ?? '';
221	        const perf = userMap[performedByKey] as
222	          | { profile?: { firstName?: string; lastName?: string } }
223	          | undefined;
224	        if (perf?.profile?.firstName)
225	          res.performedByName = `${perf.profile.firstName} ${perf.profile.lastName}`;
226	
227	        const formatActor = (
228	          actor: { type: string; id?: string } | undefined
229	        ) => {
230	          if (actor?.type === 'cashier' && actor.id) {
231	            const cashierData = userMap[actor.id] as
232	              | { profile?: { firstName?: string; lastName?: string } }
233	              | undefined;
234	            return cashierData?.profile?.firstName
235	              ? `Cashier (${cashierData.profile.firstName} ${cashierData.profile.lastName})`
236	              : `Cashier (${actor.id})`;
237	          }
238	          if (actor?.type === 'machine' && actor.id) {
239	            const machineData = machineMap[actor.id] as
240	              | { serialNumber?: string; custom?: { name?: string } }
241	              | undefined;
242	            return machineData
243	              ? `Machine (${
244	                  String(machineData.serialNumber || '').trim() ||
245	                  String(machineData.custom?.name || '').trim() ||
246	                  actor.id
247	                })`
248	              : `Machine (${actor.id})`;
249	          }
250	          return null;
251	        };
252	
253	        const fromName = formatActor(tx.from);
254	        const toName = formatActor(tx.to);
255	        if (fromName) res.fromName = fromName;
256	        if (toName) res.toName = toName;
257	
258	        const aMIds = new Set<string>();
259	        if (tx.from?.type === 'machine' && tx.from.id) aMIds.add(tx.from.id);
260	        if (tx.to?.type === 'machine' && tx.to.id) aMIds.add(tx.to.id);
261	        if (tx.expenseDetails?.machineIds?.length)
262	          tx.expenseDetails.machineIds.forEach(id => aMIds.add(id));
263	
264	        if (aMIds.size > 0) {
265	          res.machineDetails = Array.from(aMIds).map(id => {
266	            const machineData = machineMap[id] as
267	              | {
268	                  serialNumber?: string;
269	                  custom?: { name?: string };
270	                  game?: string;
271	                  installedGame?: string;
272	                  gameType?: string;
273	                }
274	              | undefined;
275	            if (!machineData)
276	              return { identifier: id, game: 'N/A', gameType: 'N/A' };
277	            const sn = String(machineData.serialNumber || '').trim();
278	            const nm = String(machineData.custom?.name || '').trim();
279	            const game = String(
280	              machineData.game || machineData.installedGame || ''
281	            );
282	            const gameType = String(machineData.gameType || '');
283	            const main = sn || nm || 'N/A';
284	            return {
285	              identifier: nm && nm !== main ? `${main} (${nm})` : main,
286	              game: game.trim(),
287	              gameType: gameType.trim(),
288	            };
289	          });
290	        }
291	        return res;
292	      });
293	
294	      // ============================================================================
295	      // Reviewer Multiplier Scaling
296	      // ============================================================================
297	      populated.forEach(transaction => {
298	        const transactionScale = getMoneyOutAndJackpotScale(
299	          userPayload as {
300	            moneyOutAndJackpotMultiplier?: number | null;
301	            roles?: string[];
302	            reviewerMultiplierStartTime?: Date | string | null;
303	          },
304	          (transaction as { timestamp?: Date | string | null }).timestamp ??
305	            null
306	        );
307	
308	        if (transactionScale !== 1 && typeof transaction.amount === 'number') {
309	          transaction.amount *= transactionScale;
310	        }
311	      });
312	
313	      populated.forEach(t => {
314	        const expenseDetails = t.expenseDetails as
315	          | {
316	              machineIds?: string[];
317	            }
318	          | undefined;
319	        if (expenseDetails?.machineIds) delete expenseDetails.machineIds;
320	      });
321	
322	      const duration = Date.now() - startTime;
323	      logRouteFetch(
324	        functionName,
325	        'GET',
326	        '/api/vault/transactions',
327	        populated.length,
328	        user,
329	        duration
330	      );
331	
332	      return NextResponse.json({
333	        success: true,
334	        items: populated,
335	        total,
336	        pagination: {
337	          page,
338	          limit,
339	          total,
340	          totalPages: Math.ceil(total / limit),
341	        },
342	      });
343	    } catch (error: unknown) {
344	      const errorMessage =
345	        error instanceof Error
346	          ? error.message
347	          : 'Failed to fetch vault transactions';
348	      logRouteError(
349	        functionName,
350	        'GET',
351	        '/api/vault/transactions',
352	        errorMessage,
353	        user
354	      );
355	      console.error('[Vault Transactions API] Error:', error);
356	      return NextResponse.json(
357	        {
358	          success: false,
359	          error: error instanceof Error ? error.message : 'Unknown error',
360	        },
361	        { status: 500 }
362	      );
363	    }
364	  });
365	}
