1	/**
2	 * Vault Transactions Page Content Component
3	 *
4	 * Transaction history page for the Vault Management application.
5	 *
6	 * Features:
7	 * - Summary metrics cards (Total Transactions, Inflow, Outflow, Expenses)
8	 * - Search and filter functionality
9	 * - Comprehensive transaction table with pagination
10	 *
11	 * @module components/VAULT/pages/VaultTransactionsPageContent
12	 */
13	'use client';
14	
15	import PageLayout from '@/components/shared/layout/PageLayout';
16	import { Badge } from '@/components/shared/ui/badge';
17	import { Button } from '@/components/shared/ui/button';
18	import { Card, CardContent } from '@/components/shared/ui/card';
19	import { Input } from '@/components/shared/ui/input';
20	import PaginationControls from '@/components/shared/ui/PaginationControls';
21	import {
22	  Select,
23	  SelectContent,
24	  SelectItem,
25	  SelectTrigger,
26	  SelectValue,
27	} from '@/components/shared/ui/select';
28	import VaultTransactionsSkeleton from '@/components/ui/skeletons/VaultTransactionsSkeleton';
29	import VaultManagerHeader from '@/components/VAULT/layout/VaultManagerHeader';
30	import { DEFAULT_POLL_INTERVAL } from '@/lib/constants';
31	import {
32	  fetchVaultTransactions,
33	  getTransactionTypeBadge,
34	} from '@/lib/helpers/vaultHelpers';
35	import { useCurrencyFormat } from '@/lib/hooks/useCurrencyFormat';
36	import { useVaultLicencee } from '@/lib/hooks/vault/useVaultLicencee';
37	import { useUserStore } from '@/lib/store/userStore';
38	import { cn } from '@/lib/utils';
39	import type { ExtendedVaultTransaction } from '@/shared/types/vault';
40	import {
41	  ArrowDown,
42	  ArrowUp,
43	  FileText,
44	  Receipt,
45	  RefreshCw,
46	  Search,
47	} from 'lucide-react';
48	import { useCallback, useEffect, useMemo, useState } from 'react';
49	import { toast } from 'sonner';
50	import VaultTransactionsMobileCards from './cards/VaultTransactionsMobileCards';
51	import type { TransactionSortOption } from './tables/VaultTransactionsTable';
52	import VaultTransactionsTable from './tables/VaultTransactionsTable';
53	
54	export default function VaultTransactionsPageContent() {
55	  // ============================================================================
56	  // State & Hooks
57	  // ============================================================================
58	  const { user } = useUserStore();
59	  const { formatAmount } = useCurrencyFormat();
60	  const { licenceeId: selectedLicencee, setLicenceeId: setSelectedLicencee } =
61	    useVaultLicencee();
62	  const isAdminOrDev = user?.roles?.some(r =>
63	    ['admin', 'developer'].includes(r.toLowerCase())
64	  );
65	  const [loading, setLoading] = useState(true);
66	  const [transactions, setTransactions] = useState<ExtendedVaultTransaction[]>(
67	    []
68	  );
69	  const [currentPage, setCurrentPage] = useState(0);
70	  const [totalPages, setTotalPages] = useState(1);
71	  const [totalItems, setTotalItems] = useState(0);
72	  const [searchTerm, setSearchTerm] = useState('');
73	  const [selectedType, setSelectedType] = useState<string>('all');
74	  const [selectedStatus, setSelectedStatus] = useState<string>('all');
75	  const [sortOption, setSortOption] = useState<TransactionSortOption>('date');
76	  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
77	
78	  // Fetch transactions
79	  const fetchData = useCallback(
80	    async (isSilent = false) => {
81	      // If Admin/Dev, allow global fetch without specific location
82	      if (!isAdminOrDev && !user?.assignedLocations?.[0]) {
83	        setLoading(false);
84	        return;
85	      }
86	
87	      const locationId = user?.assignedLocations?.[0] || 'all';
88	
89	      if (!isSilent) setLoading(true);
90	
91	      try {
92	        const data = await fetchVaultTransactions(
93	          locationId,
94	          currentPage + 1,
95	          20,
96	          selectedType,
97	          selectedStatus,
98	          searchTerm
99	        );
100	        setTransactions(data.transactions);
101	        setTotalPages(data.totalPages);
102	        setTotalItems(data.total);
103	      } catch (error) {
104	        console.error('Failed to fetch transactions', error);
105	        toast.error('Failed to load transactions');
106	      } finally {
107	        setLoading(false);
108	      }
109	    },
110	    [
111	      user?.assignedLocations,
112	      user?.roles,
113	      currentPage,
114	      selectedType,
115	      selectedStatus,
116	      searchTerm,
117	      isAdminOrDev,
118	    ]
119	  );
120	
121	  // ============================================================================
122	  // Effects
123	  // ============================================================================
124	  // Reset page when filters change
125	  useEffect(() => {
126	    setCurrentPage(0);
127	  }, [searchTerm, selectedType, selectedStatus]);
128	
129	  useEffect(() => {
130	    fetchData();
131	  }, [fetchData, selectedLicencee]);
132	
133	  // Periodic refresh only if at least 2 items
134	  useEffect(() => {
135	    if (transactions.length < 2) return;
136	
137	    const interval = setInterval(() => {
138	      fetchData(true);
139	    }, DEFAULT_POLL_INTERVAL);
140	
141	    return () => clearInterval(interval);
142	  }, [fetchData, transactions.length]);
143	
144	  // ============================================================================
145	  // Computed
146	  // ============================================================================
147	  /**
148	   * Filter and sort transactions based on search term, type, status filters, and sort options
149	   */
150	  /**
151	   * Sort transactions for the current page
152	   * (Filtering is now handled server-side)
153	   */
154	  const filteredAndSortedTransactions = useMemo(() => {
155	    // Only sort the current page data
156	    return [...transactions].sort((a, b) => {
157	      const getField = (obj: ExtendedVaultTransaction, field: string) => {
158	        switch (field) {
159	          case 'date':
160	            return new Date(obj.timestamp).getTime();
161	          case 'user':
162	            return (obj.performedByName || obj.performedBy || '').toLowerCase();
163	          case 'source':
164	            return (obj.fromName || '').toLowerCase();
165	          case 'destination':
166	            return (obj.toName || '').toLowerCase();
167	          case 'amount':
168	            return Math.abs(obj.amount);
169	          case 'type':
170	            return (obj.type || '').toLowerCase();
171	          case 'status':
172	            return obj.isVoid ? 'voided' : 'completed';
173	          default:
174	            return (obj as Record<string, unknown>)[field];
175	        }
176	      };
177	
178	      const aValue = getField(a, sortOption);
179	      const bValue = getField(b, sortOption);
180	
181	      const aStr = typeof aValue === 'number' ? aValue : String(aValue ?? '');
182	      const bStr = typeof bValue === 'number' ? bValue : String(bValue ?? '');
183	
184	      if (aStr < bStr) return sortOrder === 'asc' ? -1 : 1;
185	      if (aStr > bStr) return sortOrder === 'asc' ? 1 : -1;
186	      return 0;
187	    });
188	  }, [sortOption, sortOrder, transactions]);
189	
190	  /**
191	   * Calculate summary metrics from all transactions
192	   */
193	  const summaryMetrics = useMemo(() => {
194	    const totalTransactions = totalItems;
195	    const totalInflow = transactions
196	      .filter(tx => tx.to?.type === 'vault' && !tx.isVoid)
197	      .reduce((sum, tx) => sum + tx.amount, 0);
198	    const totalOutflow = transactions
199	      .filter(tx => tx.from?.type === 'vault' && !tx.isVoid)
200	      .reduce((sum, tx) => sum + tx.amount, 0);
201	    const totalExpenses = transactions
202	      .filter(tx => tx.type === 'expense' && !tx.isVoid)
203	      .reduce((sum, tx) => sum + tx.amount, 0);
204	
205	    return {
206	      totalTransactions,
207	      totalInflow,
208	      totalOutflow,
209	      totalExpenses,
210	    };
211	  }, [transactions, totalItems]);
212	
213	  /**
214	   * Get badge component for transaction type
215	   */
216	  const getTransactionBadge = (type: string) => {
217	    const badgeConfig = getTransactionTypeBadge(type);
218	    if (badgeConfig.icon === 'arrow-up') {
219	      return (
220	        <Badge className={badgeConfig.className}>
221	          <ArrowUp className="mr-1 h-3 w-3" />
222	          {badgeConfig.label}
223	        </Badge>
224	      );
225	    }
226	    if (badgeConfig.icon === 'arrow-down') {
227	      return (
228	        <Badge className={badgeConfig.className}>
229	          <ArrowDown className="mr-1 h-3 w-3" />
230	          {badgeConfig.label}
231	        </Badge>
232	      );
233	    }
234	    if (badgeConfig.icon === 'receipt') {
235	      return (
236	        <Badge className={badgeConfig.className}>
237	          <Receipt className="mr-1 h-3 w-3" />
238	          {badgeConfig.label}
239	        </Badge>
240	      );
241	    }
242	    return <Badge>{badgeConfig.label}</Badge>;
243	  };
244	
245	  // ============================================================================
246	  // Handlers
247	  // ============================================================================
248	  /**
249	   * Handle table column sort
250	   */
251	  const handleSort = (column: TransactionSortOption) => {
252	    if (sortOption === column) {
253	      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
254	    } else {
255	      setSortOption(column);
256	      setSortOrder('asc');
257	    }
258	  };
259	
260	  // ============================================================================
261	  // Render
262	  // ============================================================================
263	  // Guard: Show skeleton while loading first page
264	  if (loading && transactions.length === 0) {
265	    return (
266	      <PageLayout>
267	        <VaultTransactionsSkeleton />
268	      </PageLayout>
269	    );
270	  }
271	
272	  return (
273	    <PageLayout
274	      onRefresh={() => fetchData(true)}
275	      refreshing={loading}
276	      headerProps={
277	        isAdminOrDev
278	          ? {
279	              selectedLicencee,
280	              setSelectedLicencee,
281	              disabled: false,
282	            }
283	          : undefined
284	      }
285	    >
286	      <div className="space-y-6">
287	        {/* Header */}
288	        <VaultManagerHeader
289	          title={isAdminOrDev ? 'Global Transactions' : 'Transaction History'}
290	          description={
291	            isAdminOrDev
292	              ? 'Viewing all vault transactions across locations'
